import{_ as e,c as t,o,a4 as a}from"./chunks/framework.ttppV29E.js";const m=JSON.parse('{"title":"Tools and Resources","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mcp-servers/tools-and-resources.md","filePath":"docs/mcp-servers/tools-and-resources.md","lastUpdated":1773428355000}'),r={name:"docs/mcp-servers/tools-and-resources.md"},s=a('<h1 id="tools-and-resources" tabindex="-1">Tools and Resources <a class="header-anchor" href="#tools-and-resources" aria-label="Permalink to &quot;Tools and Resources&quot;">​</a></h1><p>MCP defines two ways to expose functionality to AI agents: <strong>Tools</strong> and <strong>Resources</strong>. Understanding the difference is essential for designing an effective MCP server.</p><h2 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h2><p>A Tool is an <strong>action</strong> that an AI agent can invoke. When an agent calls a tool, AireGlu executes the mapped endpoint with the agent&#39;s input and returns the result.</p><h3 id="characteristics" tabindex="-1">Characteristics <a class="header-anchor" href="#characteristics" aria-label="Permalink to &quot;Characteristics&quot;">​</a></h3><ul><li><strong>Invocable</strong> - The agent actively calls the tool with parameters</li><li><strong>Input-driven</strong> - The agent provides structured input (JSON or XML) matching the endpoint&#39;s schema</li><li><strong>Side effects expected</strong> - Tools typically perform operations: sending emails, submitting data, triggering workflows</li><li><strong>Schema-aware</strong> - AireGlu automatically generates a JSON Schema from the target endpoint&#39;s configuration, which the agent uses to construct valid input</li></ul><h3 id="when-to-use-tools" tabindex="-1">When to Use Tools <a class="header-anchor" href="#when-to-use-tools" aria-label="Permalink to &quot;When to Use Tools&quot;">​</a></h3><p>Use a Tool when the endpoint:</p><ul><li>Performs an action (send, create, update, delete, trigger)</li><li>Requires input from the agent</li><li>Produces a result based on that input</li><li>Has side effects (writes data, sends messages, starts processes)</li></ul><h3 id="how-tools-work-at-runtime" tabindex="-1">How Tools Work at Runtime <a class="header-anchor" href="#how-tools-work-at-runtime" aria-label="Permalink to &quot;How Tools Work at Runtime&quot;">​</a></h3><ol><li>The AI agent calls <code>tools/call</code> with the tool name and input arguments</li><li>AireGlu matches the tool name to the configured exposed endpoint</li><li>The endpoint executes with the provided input</li><li>The endpoint response is returned to the agent as the tool result</li></ol><h3 id="input-schema-generation" tabindex="-1">Input Schema Generation <a class="header-anchor" href="#input-schema-generation" aria-label="Permalink to &quot;Input Schema Generation&quot;">​</a></h3><p>AireGlu generates the tool&#39;s input schema automatically from the target endpoint:</p><ul><li><strong>JSON endpoints</strong> - The endpoint&#39;s configured JSON schema is used directly. If no schema is defined, an empty object schema is provided.</li><li><strong>XML endpoints</strong> - An enhanced schema is generated from the endpoint&#39;s XSD, including documentation elements from the XSD as descriptions.</li><li><strong>Other formats</strong> (HL7, plain text) - A string content schema is generated with instruction text describing the expected format.</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><p>A Resource is <strong>data</strong> that an AI agent can read. When an agent reads a resource, AireGlu executes the mapped endpoint with no input and returns the response.</p><h3 id="characteristics-1" tabindex="-1">Characteristics <a class="header-anchor" href="#characteristics-1" aria-label="Permalink to &quot;Characteristics&quot;">​</a></h3><ul><li><strong>Readable</strong> - The agent reads the resource to retrieve data</li><li><strong>No input</strong> - Resources are invoked with an empty payload (<code>{}</code>)</li><li><strong>Identified by URI</strong> - Each resource has a unique URI (e.g. <code>data://patient-list</code>)</li><li><strong>Content-typed</strong> - Each resource declares its MIME type (e.g. <code>application/json</code>)</li></ul><h3 id="when-to-use-resources" tabindex="-1">When to Use Resources <a class="header-anchor" href="#when-to-use-resources" aria-label="Permalink to &quot;When to Use Resources&quot;">​</a></h3><p>Use a Resource when the endpoint:</p><ul><li>Returns data without requiring input</li><li>Provides context or reference information</li><li>Acts as a data source for the agent&#39;s reasoning</li><li>Does not have meaningful side effects</li></ul><h3 id="how-resources-work-at-runtime" tabindex="-1">How Resources Work at Runtime <a class="header-anchor" href="#how-resources-work-at-runtime" aria-label="Permalink to &quot;How Resources Work at Runtime&quot;">​</a></h3><ol><li>The AI agent calls <code>resources/read</code> with the resource URI</li><li>AireGlu matches the URI to the configured exposed endpoint</li><li>The response is returned with the configured MIME type</li></ol><h3 id="resource-uris" tabindex="-1">Resource URIs <a class="header-anchor" href="#resource-uris" aria-label="Permalink to &quot;Resource URIs&quot;">​</a></h3><p>Each Resource requires a unique URI. Choose a descriptive scheme:</p><table><thead><tr><th>URI Pattern</th><th>Use Case</th></tr></thead><tbody><tr><td><code>data://patient-records</code></td><td>Data retrieval</td></tr><tr><td><code>file://config.json</code></td><td>Configuration data</td></tr><tr><td><code>aireglu://&lt;server&gt;/&lt;name&gt;</code></td><td>Generic AireGlu resource</td></tr></tbody></table><p>If no URI is specified, AireGlu auto-generates one in the format <code>aireglu://&lt;server-name&gt;/&lt;endpoint-name&gt;</code>.</p><p>URIs must be unique within a version (case-insensitive).</p><h2 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h2><table><thead><tr><th>Aspect</th><th>Tool</th><th>Resource</th></tr></thead><tbody><tr><td>Agent action</td><td>Calls with input</td><td>Reads by URI</td></tr><tr><td>Input</td><td>Structured (JSON/XML)</td><td>None (empty payload)</td></tr><tr><td>Purpose</td><td>Perform an action</td><td>Retrieve data</td></tr><tr><td>Side effects</td><td>Expected</td><td>Not expected</td></tr><tr><td>Identified by</td><td>Name</td><td>URI</td></tr><tr><td>Schema</td><td>Auto-generated from endpoint</td><td>Not applicable</td></tr><tr><td>MIME type</td><td>N/A</td><td>Configurable (default: <code>application/json</code>)</td></tr></tbody></table><h2 id="choosing-between-tool-and-resource" tabindex="-1">Choosing Between Tool and Resource <a class="header-anchor" href="#choosing-between-tool-and-resource" aria-label="Permalink to &quot;Choosing Between Tool and Resource&quot;">​</a></h2><p>Ask yourself: <strong>Does the AI agent need to send data to get a result?</strong></p><ul><li><strong>Yes</strong> → Use a <strong>Tool</strong>. The agent provides input, and the endpoint processes it.</li><li><strong>No</strong> → Use a <strong>Resource</strong>. The agent just needs to read the output.</li></ul><h3 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h3><table><thead><tr><th>Scenario</th><th>Type</th><th>Reason</th></tr></thead><tbody><tr><td>Send an email</td><td>Tool</td><td>Requires input (recipient, subject, body)</td></tr><tr><td>Look up a patient by NHS number</td><td>Tool</td><td>Requires input (the NHS number)</td></tr><tr><td>Retrieve a list of supported regions</td><td>Resource</td><td>No input needed, returns static/semi-static data</td></tr><tr><td>Fetch today&#39;s appointment schedule</td><td>Resource</td><td>No input needed, returns current data</td></tr><tr><td>Submit a form to an external API</td><td>Tool</td><td>Requires structured input</td></tr><tr><td>Read system configuration</td><td>Resource</td><td>No input needed</td></tr></tbody></table><h2 id="restrictions" tabindex="-1">Restrictions <a class="header-anchor" href="#restrictions" aria-label="Permalink to &quot;Restrictions&quot;">​</a></h2><p>The following endpoint types <strong>cannot</strong> be exposed via MCP:</p><ul><li>Endpoints with <strong>Callback</strong> input mode</li><li>Endpoints with <strong>AdapterCallback</strong> input mode</li></ul><p>These modes require interactive or asynchronous input mechanisms that are incompatible with the MCP request-response model.</p>',39),n=[s];function i(d,l,c,h,u,p){return o(),t("div",null,n)}const f=e(r,[["render",i]]);export{m as __pageData,f as default};
